func solve(nums: Array<Int64>, k: Int64) -> Int64 {
    var prefixSum = 0
    var modCounts = [Int64: Int64]()
    modCounts[0] = 1

    for num in nums {
        prefixSum += num
        let mod = prefixSum % k
        modCounts[mod] = modCounts[mod, default: 0] + 1
    }

    var minSum = Int64.max
    for (mod, count) in modCounts {
        if count > 0 {
            let sum = (k * count) - mod
            minSum = min(minSum, sum)
        }
    }

    return minSum
}
