int64_t solve(Array<Int64> nums, Int64 k) {
    int n = nums.length;
    int64_t totalSum = 0;
    for (int i = 0; i < n; i++) {
        totalSum += nums[i];
    }

    // If k is 1, all elements can be removed, so the minimum sum is 0
    if (k == 1) {
        return 0;
    }

    // Use a prefix sum array to track cumulative sums modulo k
    int64_t prefixSum = 0;
    int64_t* prefixMod = (int64_t*)malloc(n * sizeof(int64_t));
    prefixMod[0] = prefixSum % k;

    for (int i = 1; i < n; i++) {
        prefixSum += nums[i];
        prefixMod[i] = prefixSum % k;
    }

    // Count the frequency of each modulo value
    int64_t* modCount = (int64_t*)malloc(k * sizeof(int64_t));
    for (int i = 0; i < k; i++) {
        modCount[i] = 0;
    }

    for (int i = 0; i < n; i++) {
        modCount[prefixMod[i]]++;
    }

    // Calculate the minimum possible sum by subtracting the maximum possible sum of removed subarrays
    int64_t maxRemovableSum = 0;
    for (int i = 0; i < k; i++) {
        if (modCount[i] > 0) {
            int64_t count = modCount[i];
            int64_t maxSum = (count / 2) * k;
            maxRemovableSum += maxSum;
        }
    }

    return totalSum - maxRemovableSum;
}
